import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";

export async function main() {
  const screened = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "find_moderate_probability_bets",
    args: {
      minPrice: 0.4,
      maxPrice: 0.6,
      minLiquidity: 1000000,
      limit: 10,
      sortBy: "liquidity",
      category: "all"
    }
  });

  const opportunities = Array.isArray(screened?.opportunities) ? screened.opportunities : [];
  const topCandidates = opportunities.slice(0, 3);

  const liquidityChecks = topCandidates.length
    ? await callMcpSkillsParallel({
        label: "moderate-probability-liquidity-checks",
        calls: topCandidates.map((market, idx) => ({
          key: String(idx),
          toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
          toolName: "analyze_market_liquidity",
          args: {
            slug: market.slug
          }
        }))
      })
    : { results: [], summary: {} };

  const liquidityByKey = Object.fromEntries(
    (liquidityChecks.results || []).map((entry) => [
      entry.key,
      entry.status === "fulfilled" ? entry.value : null
    ])
  );

  const tradability = topCandidates.map((market, idx) => {
    const liq = liquidityByKey[String(idx)];
    return {
      market: market.market,
      url: market.url,
      currentPrice: market.currentPrice,
      liquidity: market.liquidity,
      volume24h: market.volume24h,
      conditionId: market.conditionId,
      opportunityType: market.opportunityType,
      suggestedSide: market.suggestedSide,
      potentialReturn: market.potentialReturn,
      impliedProbability: market.impliedProbability,
      tradabilityAssessment: liq
        ? {
            liquidityScore: liq.liquidityScore,
            spread: liq.spread,
            whaleCost: liq.whaleCost,
            depth: liq.depth,
            recommendation: liq.recommendation,
            fetchedAt: liq.fetchedAt
          }
        : null
    };
  });

  const sorted = [...tradability].sort((a, b) => (b.liquidity || 0) - (a.liquidity || 0));

  return {
    filters: {
      minPrice: 0.4,
      maxPrice: 0.6,
      minLiquidity: 1000000,
      category: "all"
    },
    totalMatches: opportunities.length,
    screenedCount: screened?.summary?.marketsScanned,
    fetchedAt: screened?.fetchedAt,
    markets: sorted,
    notes: [
      "This answer is based on a live Polymarket query and follow-up liquidity checks from the current tool run.",
      "A market is more tradable in size when it keeps a strong liquidityScore and shallow whale-cost/slippage on the size you care about."
    ]
  };
}

