export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "find_arbitrage_opportunities",
    args: {
      category: "politics",
      limit: 20
    }
  });

  const arbitrageOpportunities = Array.isArray(result?.arbitrageOpportunities)
    ? result.arbitrageOpportunities
    : [];
  const wideSpreadMarkets = Array.isArray(result?.wideSpreadMarkets)
    ? result.wideSpreadMarkets
    : [];

  const passiveCandidates = wideSpreadMarkets
    .filter((m) => typeof m?.spread === "number" && typeof m?.midPrice === "number")
    .map((m) => ({
      market: m.market,
      url: m.url,
      spread: m.spread,
      midPrice: m.midPrice,
      spreadPercent: m.spreadPercent,
      passiveOrderAppeal: m.spread <= 0.06 ? "better" : m.spread <= 0.12 ? "okay" : "wide"
    }))
    .sort((a, b) => a.spread - b.spread);

