import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";


function __normalizeToolArrayOutput(value) {
  if (Array.isArray(value)) {
    return value;
  }
  if (!value || typeof value !== "object") {
    return [];
  }

  const directCandidates = [
    value.results,
    value.items,
    value.rows,
    value.markets,
    value.events,
    value.entries,
    value.records,
    value.candidates,
    value.data,
  ];

  for (const candidate of directCandidates) {
    if (Array.isArray(candidate)) {
      return candidate;
    }
  }

  const nestedData =
    value.data && typeof value.data === "object" ? value.data : null;
  if (!nestedData) {
    return [];
  }

  const nestedCandidates = [
    nestedData.results,
    nestedData.items,
    nestedData.rows,
    nestedData.markets,
    nestedData.events,
    nestedData.entries,
    nestedData.records,
    nestedData.candidates,
    nestedData.data,
  ];

  for (const candidate of nestedCandidates) {
    if (Array.isArray(candidate)) {
      return candidate;
    }
  }

  return [];
}

export async function main() {
  const topMarkets = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "get_top_markets",
    args: {
      category: "politics",
      sortBy: "liquidity",
      limit: 10
    }
  });

  const markets = Array.isArray(topMarkets?.markets) ? topMarkets.markets : [];
  const shortlisted = markets.filter((m) => m && (m.slug || m.conditionId || m.title));

  const rankedCandidates = pickTopSemanticCandidates({
    target: "most liquid live multi-outcome politics event",
    candidates: shortlisted,
    requiredTerms: ["politics"],
    avoidTerms: ["yes/no", "binary"],
    limit: 3
  });

  const chosen = rankedCandidates?.[0] || shortlisted[0];

  if (!chosen) {
    return {
      missingData: ["No live politics markets returned"],
      attemptedBranches: ["get_top_markets(category=politics, sortBy=liquidity, limit=10)"],
      stopReason: "No candidate market found"
    };
  }

  const parallel = await callMcpSkillsParallel({
    label: "politics-event-resolve-and-validate",
    calls: [
      {
        key: "event-outcomes",
        toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
        toolName: "search_and_get_outcomes",
        args: {
          query: chosen.title || chosen.slug || "politics event",
          category: "politics"
        }
      },
      {
        key: "market-rules",
        toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
        toolName: "check_market_rules",
        args: {
          slug: chosen.slug
        }
      },
      {
        key: "market-efficiency",
        toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
        toolName: "check_market_efficiency",
        args: {
          slug: chosen.slug
        }
      }
    ]
  });

  const resultsByKey = Object.fromEntries(
    __normalizeToolArrayOutput(parallel.results).map((entry) => [
      entry.key,
      entry.status === "fulfilled" ? entry.value : null
    ])
  );

  const eventData = resultsByKey["event-outcomes"];
  const rulesData = resultsByKey["market-rules"];
  const efficiencyData = resultsByKey["market-efficiency"];

  const outcomes = Array.isArray(eventData?.outcomes) ? eventData.outcomes : [];
  const topFourOutcomes = outcomes
    .filter((o) => o && typeof o.name === "string" && typeof o.price === "number")
    .sort((a, b) => b.price - a.price)
    .slice(0, 4)
    .map((o) => o.name);

  if (topFourOutcomes.length === 0) {
    return {
      selectedMarket: {
        title: chosen.title || null,
        slug: chosen.slug || null,
        conditionId: chosen.conditionId || null
      },
      missingData: ["No outcomes returned for selected market"],
      attemptedBranches: [
        "get_top_markets(category=politics, sortBy=liquidity, limit=10)",
        "search_and_get_outcomes(query=chosen.title)",
        "check_market_rules(slug=chosen.slug)",
        "check_market_efficiency(slug=chosen.slug)"
      ],
      stopReason: "Could not resolve top outcomes",
      parallelTelemetry: parallel.summary
    };
  }

  const outcomeLiquidity = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "analyze_event_outcome_liquidity",
    args: {
      slug: eventData?.eventSlug || chosen.slug,
      outcomes: topFourOutcomes,
      limit: 4,
      sortBy: "volume"
    }
  });

  const analyzedOutcomes = Array.isArray(outcomeLiquidity?.analyzedOutcomes)
