import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  // 1) Probe with parallel read-only discovery across different endpoints.
  const batch = await callMcpSkillsParallel({
    label: "iran-escalation-discovery",
    calls: [
      {
        key: "search_markets",
        toolId,
        toolName: "search_markets",
        args: {
          query: "live Iran escalation risk",
          status: "live",
          category: "politics",
          limit: 25
        }
      },
      {
        key: "discover_trending_markets",
        toolId,
        toolName: "discover_trending_markets",
        args: {
          category: "politics",
          limit: 25,
          sortBy: "volume"
        }
      }
    ]
  });

  const searchRes =
    batch.results.find((r) => r.key === "search_markets")?.status === "fulfilled"
      ? batch.results.find((r) => r.key === "search_markets")?.value
      : null;

  const trendRes =
    batch.results.find((r) => r.key === "discover_trending_markets")?.status === "fulfilled"
      ? batch.results.find((r) => r.key === "discover_trending_markets")?.value
      : null;

  const searchCandidates = Array.isArray(searchRes?.results) ? searchRes.results : [];
  const trendCandidates = Array.isArray(trendRes?.trendingMarkets) ? trendRes.trendingMarkets : [];

  const combined = [...searchCandidates, ...trendCandidates].filter(Boolean);

  // 2) Deterministically rank the full candidate set before any selection.
  const ranked = pickTopSemanticCandidates({
    target: "live Polymarket contracts that directly encode Iran escalation risk or direct Iran military conflict thesis",
    candidates: combined,
    requiredTerms: ["iran"],
    avoidTerms: ["lunch", "primary", "approval", "poll", "speaker", "district"],
    limit: 8
  });

  const shortlist = ranked.map((item) => ({
    title: item?.title || item?.market || "",
    slug: item?.slug,
    conditionId: item?.conditionId,
    url: item?.url,
    category: item?.category,
    liquidity: item?.liquidity,
    volume: item?.volume,
    currentPrice: item?.currentPrice,
    status: item?.status,
    whySelected: item?.reason || item?.whyTrending || item?.signal || ""
  }));

  // 3) Sequential same-endpoint exploration for shortlisted contracts only.
  const enriched = [];
  for (const item of shortlist) {
    if (!item.slug && !item.conditionId) continue;

    const rules = await callMcpSkill({
      toolId,
      toolName: "check_market_rules",
      args: item.slug ? { slug: item.slug } : { conditionId: item.conditionId }
    });

    enriched.push({
      ...item,
      market: rules?.market,
      description: rules?.description,
      endDate: rules?.endDate,
      resolutionSource: rules?.resolutionSource,
      rulesSummary: rules?.rulesSummary,
      riskFactors: Array.isArray(rules?.riskFactors) ? rules.riskFactors : [],
      ruleGaps: {
        ambiguities: rules?.rulesSummary?.ambiguities || [],
        gotchas: rules?.rulesSummary?.potentialGotchas || []
      }
    });
  }

  // 4) Local analysis only after the read batch completes.
  const scored = enriched
    .map((m) => {
      const title = String(m.title || "").toLowerCase();
      const desc = String(m.description || "").toLowerCase();
      const rulesText = JSON.stringify(m.rulesSummary || {}).toLowerCase();

      const directness =
        (title.includes("iran") ? 3 : 0) +
        (desc.includes("iran") ? 2 : 0) +
        (rulesText.includes("iran") ? 2 : 0) +
        (title.includes("escalation") || desc.includes("escalation") ? 2 : 0) +
        (title.includes("attack") || title.includes("strike") || desc.includes("attack") || desc.includes("strike") ? 2 : 0) +
        (String(m.endDate || "").length > 0 ? 1 : 0);

      const thesisCleanliness =
        (rulesText.includes("by") || rulesText.includes("before") ? 1 : 0) +
        (rulesText.includes("resolution source") ? 1 : 0) +
        (m.slug ? 1 : 0);

      return {
        ...m,
        directnessScore: directness,
        thesisCleanlinessScore: thesisCleanliness,
        totalScore: directness * 2 + thesisCleanliness
      };
    })
    .sort((a, b) => b.totalScore - a.totalScore);

  const cleanest = scored[0] || null;

  return {
    intent: "live Iran escalation risk",
    discovery: {
      searchMarketCount: searchCandidates.length,
      trendingMarketCount: trendCandidates.length,
      combinedCandidateCount: combined.length
    },
    shortlist: enriched.map((m) => ({
      title: m.title,
