      conditionId: m.conditionId,
      url: m.url,
      currentPrice: m.currentPrice,
      liquidity: m.liquidity,
      volume: m.volume,
      endDate: m.endDate,
      resolutionSource: m.resolutionSource,
      directnessScore: m.directnessScore,
      thesisCleanlinessScore: m.thesisCleanliness

