export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const topMarkets = await callMcpSkill({
    toolId,
    toolName: "get_top_markets",
    args: {
      limit: 100,
      sortBy: "total_volume",
      includeNearResolved: false,
      includeEnded: false
    }
  });

  const markets = Array.isArray(topMarkets?.markets) ? topMarkets.markets : [];

  const moderate = markets.filter((m) => {
    const price = typeof m?.currentPrice === "number" ? m.currentPrice : null;
    const totalVolume = typeof m?.totalVolume === "number" ? m.totalVolume : null;
    const liquidity = typeof m?.liquidity === "number" ? m.liquidity : null;
    return (
      price !== null &&
      totalVolume !== null &&
      liquidity !== null &&
      price >= 0.4 &&
      price <= 0.75 &&
      totalVolume >= 10000000 &&
      liquidity >= 5000
    );
  });

  const scored = moderate
    .map((m) => {
      const price = m.currentPrice;
      const totalVolume = m.totalVolume;
      const liquidity = m.liquidity;
      const upside = (1 - price) / Math.max(price, 0.0001);
      const liquidityBonus = Math.log10(Math.max(liquidity, 1));
      const volumeBonus = Math.log10(Math.max(totalVolume, 1)) - 6;
      const score = upside * 100 + liquidityBonus * 10 + volumeBonus * 5;

      return {
        title: m.title,
        url: m.url,
        slug: m.slug,
        conditionId: m.conditionId,
        category: m.category,
        endDate: m.endDate,
        currentPrice: price,
        totalVolume,
        liquidity,
        volume24h: m.volume24h,
        riskRewardScore: Number(score.toFixed(2)),
        impliedUpsideMultiple: Number(upside.toFixed(2))
      };
    })
    .sort((a, b) => b.riskRewardScore - a.riskRewardScore);

  const shortlist = scored.slice(0, 5);

  const liquidityChecks = [];
  for (const m of shortlist) {
    const liq = await callMcpSkill({
      toolId,
      toolName: "analyze_market_liquidity",
      args: {
        slug: m.slug
      }
    });
    liquidityChecks.push({
      title: m.title,
      slug: m.slug,
      currentPrice: m.currentPrice,
      totalVolume: m.totalVolume,
      liquidity: m.liquidity,
      spread: liq?.spread,
      liquidityScore: liq?.liquidityScore,
      whaleCost: liq?.whaleCost,
      recommendation: liq?.recommendation,
      fetchedAt: liq?.fetchedAt
    });
  }

  const ranked = liquidityChecks
    .map((m) => {
      const spreadBps = typeof m.spread?.bps === "number" ? m.spread.bps : null;
      const spreadPenalty = spreadBps === null ? 0 : spreadBps / 10;
      const liquidityScoreBonus =
        m.liquidityScore === "excellent" ? 25 :
        m.liquidityScore === "good" ? 15 :
        m.liquidityScore === "moderate" ? 5 : 0;

      const baseScore =
        ((1 - m.currentPrice) / Math.max(m.currentPrice, 0.0001)) * 100 +
        Math.log10(Math.max(m.totalVolume, 1)) * 5 +
        Math.log10(Math.max(m.liquidity, 1)) * 10 +
        liquidityScoreBonus -
        spreadPenalty;

      return {
        ...m,
        spreadBps,
        riskRewardScore: Number(baseScore.toFixed(2))
      };
    })
    .sort((a, b) => b.riskRewardScore - a.riskRewardScore);

  return {
    filters: {
      priceRange: [0.4, 0.75],
      minTotalVolume: 10000000,
      minLiquidity: 5000,
      liveOnly: true,
      positionSizeCheck: "$5k"
    },
    totalCandidates: markets.length,
    matchedCandidates: scored.length,
    rankedBets: ranked.map((m, i) => ({
      rank: i + 1,
      title: m.title,
      url: m.url,
      currentPrice: m.currentPrice,
      totalVolume: m.totalVolume,
      liquidity: m.liquidity,
      spreadBps: m.spreadBps,
      liquidityScore: m.liquidityScore,
      riskRewardScore: m.riskRewardScore,
      impliedUpsideMultiple: m.impliedUpsideMultiple,
      recommendation: m.recommendation,
      whaleCost: m.whaleCost
    })),
    note: "Risk/reward ranking is a derived proxy based on upside, total volume, liquidity, and spread. I used the current live Polymarket data from this query."
  };
}

